import argparse
import os


def write_bytes(file, source_path):
    with open(source_path, mode="rb") as binary:
        buffer = binary.read()
        buffer = buffer[148:]  # skip .dds header

        file.write("0x{:02x}".format(buffer[0]))
        for byte in range(1, len(buffer)):
            file.write(",0x{:02x}".format(buffer[byte]))


def make_ltc_lut(target, sources):
    with open(target, "w", encoding="utf-8", newline="\n") as file:
        file.write(
            '/* WARNING, THIS FILE WAS GENERATED BY THE "{}" SCRIPT, DO NOT EDIT */ \n\n'.format(
                os.path.basename(sources[0])
            )
        )

        file.write(
            "// LTC Lookup table for BRDF fitting by Eric Heitz (https://eheitzresearch.wordpress.com/415-2/) \n"
        )
        file.write("static const int LTC_LUT_DIMENSIONS = 64; // 64x64\n")
        file.write("static const uint8_t LTC_LUT1[] = {")
        write_bytes(file, sources[1])
        file.write("};\n\n")

        file.write("static const uint8_t LTC_LUT2[] = {")
        write_bytes(file, sources[2])
        file.write("};\n\n")


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--target", required=True, help="Target file")
    parser.add_argument("--source", nargs="+", required=True, help="Source file(s)")
    args = parser.parse_args()

    make_ltc_lut(args.target, args.source)


if __name__ == "__main__":
    main()
